code = """import json
import re
import os

# Load full business data
business_data_file = locals()['var_functions.query_db:52']
if isinstance(business_data_file, str) and os.path.exists(business_data_file):
    with open(business_data_file, 'r') as f:
        business_data = json.load(f)
else:
    business_data = locals()['var_functions.query_db:52']

ratings_data = locals()['var_functions.query_db:48']
ratings_dict = {}
for item in ratings_data:
    ratings_dict[item['gmap_id']] = float(item['avg_rating'])

# Function to check if business is open AFTER 6PM on any weekday
def is_open_after_6pm(hours_str):
    if not hours_str or hours_str == 'None':
        return False
    
    try:
        hours_list = eval(hours_str)
        if not isinstance(hours_list, list):
            return False
        
        weekdays = {'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'}
        
        for entry in hours_list:
            if len(entry) != 2:
                continue
                
            day, time_range = entry
            if day not in weekdays:
                continue
                
            if time_range == 'Open 24 hours':
                return True
            if time_range == 'Closed':
                continue
            
            closing = None
            for dash_char in ['\\u2013', '\\u2014', '-']:
                if dash_char in time_range:
                    parts = time_range.split(dash_char)
                    if len(parts) >= 2:
                        closing = parts[1].strip()
                        break
            
            if not closing:
                continue
            
            if 'PM' in closing.upper():
                hour_match = re.search(r'(\d{1,2})(?::\d{2})?\s*PM', closing, re.IGNORECASE)
                if hour_match:
                    hour = int(hour_match.group(1))
                    if hour == 12:
                        continue
                    hour += 12
                    if hour > 18:
                        return True
        
        return False
    except:
        return False

# Filter and rank businesses
open_late_businesses = []
for business in business_data:
    gmap_id = business['gmap_id']
    hours = business['hours']
    avg_rating = ratings_dict.get(gmap_id, 0.0)
    
    if avg_rating > 0 and is_open_after_6pm(hours):
        open_late_businesses.append({
            'name': business['name'],
            'gmap_id': gmap_id,
            'hours': hours,
            'avg_rating': avg_rating
        })

open_late_businesses.sort(key=lambda x: x['avg_rating'], reverse=True)
top_5 = open_late_businesses[:5]

results = []
for i, biz in enumerate(top_5, 1):
    results.append({
        'rank': i,
        'name': biz['name'],
        'hours': biz['hours'],
        'avg_rating': round(biz['avg_rating'], 2)
    })

print('__RESULT__:')
print(json.dumps(results))"""

